inline:<div id="header-root">
  <style>
    #header-root { background: #0A0A12; min-height: 60vh; display: flex; flex-direction: column; align-items: center; justify-content: center; color: white; font-family: 'Montserrat', sans-serif; }
    .c1-workshop { color: #FF00E5; font-family: 'JetBrains Mono', monospace; font-size: 14px; letter-spacing: 4px; }
    .c1-main-h { font-size: clamp(3rem, 8vw, 6rem); color: #00F2FF; text-align: center; margin: 20px 0; }
    #header-root-canvas { width: 300px; height: 300px; }
  </style>
  <div class="c1-workshop">WORKSHOP // DNA_WONDERS</div>
  <h1 class="c1-main-h">DECODING THE SPIRAL</h1>
  <canvas id="header-root-canvas"></canvas>
  <script>
    let rafId;
    window.c1_mount = () => {
      c1_initializeHeaderAnimation();
    };
    window.c1_destroy = () => {
      cancelAnimationFrame(rafId);
    };
    window.c1_initializeHeaderAnimation = () => {
      const canvas = document.getElementById('header-root-canvas');
      if (!canvas || window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
      const ctx = canvas.getContext('2d');
      let angle = 0;
      const render = () => {
        ctx.clearRect(0,0,300,300);
        ctx.strokeStyle = '#00F2FF';
        ctx.beginPath();
        ctx.arc(150, 150, 80, angle, angle + Math.PI);
        ctx.stroke();
        angle += 0.05;
        rafId = requestAnimationFrame(render);
      };
      render();
    };
  </script>
</div>
